import 'package:dartz/dartz.dart'; import 'package:dio/dio.dart'; import 'package:myguard_frontend/core/error/exceptions.dart'; import 'package:myguard_frontend/core/error/failures.dart'; import 'package:myguard_frontend/core/network/paginated_response_model.dart'; import 'package:myguard_frontend/features/emergency/data/datasources/emergency_remote_datasource.dart'; import 'package:myguard_frontend/features/emergency/domain/entities/emergency_entity.dart'; import 'package:myguard_frontend/features/emergency/domain/repositories/emergency_repository.dart';

class EmergencyRepositoryImpl implements EmergencyRepository {
  const EmergencyRepositoryImpl({required this.remoteDatasource}); final EmergencyRemoteDatasource remoteDatasource;
  Failure _m(DioException e) { final er = e.error; if (er is NetworkException) return const NetworkFailure(); if (er is ServerException) return ServerFailure(er.message ?? 'Error'); return const UnknownFailure(); }
  @override Future<Either<Failure, PanicAlertEntity>> triggerPanic(Map<String, dynamic> data) async { try { return Right(await remoteDatasource.triggerPanic(data)); } on DioException catch (e) { return Left(_m(e)); } catch (e) { return Left(UnknownFailure(e.toString())); } }
  @override Future<Either<Failure, PaginatedResponseModel<PanicAlertEntity>>> getPanicAlerts({int page = 0, int size = 20, String? societyId}) async { try { return Right(await remoteDatasource.getPanicAlerts(page: page, size: size, societyId: societyId)); } on DioException catch (e) { return Left(_m(e)); } catch (e) { return Left(UnknownFailure(e.toString())); } }
  @override Future<Either<Failure, PanicAlertEntity>> resolvePanic(String id) async { try { return Right(await remoteDatasource.resolvePanic(id)); } on DioException catch (e) { return Left(_m(e)); } catch (e) { return Left(UnknownFailure(e.toString())); } }
  @override Future<Either<Failure, PaginatedResponseModel<EmergencyContactEntity>>> getEmergencyContacts({int page = 0, int size = 20, String? societyId}) async { try { return Right(await remoteDatasource.getContacts(page: page, size: size, societyId: societyId)); } on DioException catch (e) { return Left(_m(e)); } catch (e) { return Left(UnknownFailure(e.toString())); } }
  @override Future<Either<Failure, EmergencyContactEntity>> createContact(Map<String, dynamic> data) async { try { return Right(await remoteDatasource.createContact(data)); } on DioException catch (e) { return Left(_m(e)); } catch (e) { return Left(UnknownFailure(e.toString())); } }
  @override Future<Either<Failure, EmergencyContactEntity>> updateContact(String id, Map<String, dynamic> data) async { try { return Right(await remoteDatasource.updateContact(id, data)); } on DioException catch (e) { return Left(_m(e)); } catch (e) { return Left(UnknownFailure(e.toString())); } }
  @override Future<Either<Failure, void>> deleteContact(String id) async { try { await remoteDatasource.deleteContact(id); return const Right(null); } on DioException catch (e) { return Left(_m(e)); } catch (e) { return Left(UnknownFailure(e.toString())); } }
}
